			"reason":       reason,
			"project_root": runtime.ProjectRoot,
			"dirty_paths":  dirtyPaths,
			"retry_after":  retryAfter,
			"message":      message,
		})
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", message)
		}
		return executeBeadIterationOutcome{Stop: true}, nil
	}
